// =================================================================================================
// PAYFAST ITN VERIFICATION WHEN n8n PROVIDES ONLY JSON BODY (NO rawBody)
// - Uses insertion order from $input.item.json.body
// - Includes empty fields (param=)
// - Excludes only `signature`
// - No passphrase (leave blank unless your PF dashboard has one)
// - Inline MD5
// =================================================================================================

const passphrase = 'PassPhrase001'; // set only if enabled in PayFast dashboard

// 1) Get body as received from Webhook node
const pf = $input.item.json.body;
if (!pf || typeof pf !== 'object') {
  throw new Error('PayFast ITN: body missing or not an object.');
}

// 2) PHP-style encoder (spaces => +, and encode like PHP)
function phpEncode(str) {
  return encodeURIComponent(String(str))
    .replace(/%20/g, '+')
    .replace(/[!'()~]/g, escape);
}

// 3) Build param string in original key order; include empty values; exclude `signature`
let receivedSignature = '';
const parts = [];
for (const [k, v] of Object.entries(pf)) {
  if (k === 'signature') {
    receivedSignature = String(v || '');
    continue;
  }
  const val = v == null ? '' : String(v);
  // include even when empty
  parts.push(`${k}=${phpEncode(val)}`);
}
let paramString = parts.join('&');

// Append passphrase only if configured
if (passphrase) {
  paramString += `&passphrase=${phpEncode(passphrase)}`;
}

// 4) Inline MD5 (no crypto)
function md5(string) {
  function RL(x, n){return (x<<n)|(x>>> (32-n));}
  function AU(x,y){const l=(x&0xffff)+(y&0xffff);return ((x>>>16)+(y>>>16)+(l>>>16)<<16)|(l&0xffff);}
  function F(x,y,z){return (x&y)|((~x)&z);} function G(x,y,z){return (x&z)|(y&(~z));}
  function H(x,y,z){return x^y^z;}         function I(x,y,z){return y^(x|(~z));}
  function FF(a,b,c,d,x,s,t){return AU(RL(AU(AU(a,F(b,c,d)),AU(x,t)),s),b);}
  function GG(a,b,c,d,x,s,t){return AU(RL(AU(AU(a,G(b,c,d)),AU(x,t)),s),b);}
  function HH(a,b,c,d,x,s,t){return AU(RL(AU(AU(a,H(b,c,d)),AU(x,t)),s),b);}
  function II(a,b,c,d,x,s,t){return AU(RL(AU(AU(a,I(b,c,d)),AU(x,t)),s),b);}
  function CTWA(s){
    const l=s.length; const n=(((l+8)>>>6)+1)*16; const w=new Array(n).fill(0);
    for(let i=0;i<l;i++){w[i>>2]|=s.charCodeAt(i)<<((i%4)*8);} 
    w[l>>2]|=0x80<<((l%4)*8); w[n-2]=l<<3; w[n-1]=l>>>29; return w;
  }
  function W2H(v){let r='';for(let i=0;i<4;i++){const b=(v>>> (i*8))&255;r+=('0'+b.toString(16)).slice(-2);}return r;}
  const x=CTWA(string); let a=0x67452301,b=0xefcdab89,c=0x98badcfe,d=0x10325476;
  for(let i=0;i<x.length;i+=16){
    const oa=a,ob=b,oc=c,od=d;
    a=FF(a,b,c,d,x[i+0],7,0xd76aa478); d=FF(d,a,b,c,x[i+1],12,0xe8c7b756);
    c=FF(c,d,a,b,x[i+2],17,0x242070db); b=FF(b,c,d,a,x[i+3],22,0xc1bdceee);
    a=FF(a,b,c,d,x[i+4],7,0xf57c0faf); d=FF(d,a,b,c,x[i+5],12,0x4787c62a);
    c=FF(c,d,a,b,x[i+6],17,0xa8304613); b=FF(b,c,d,a,x[i+7],22,0xfd469501);
    a=FF(a,b,c,d,x[i+8],7,0x698098d8); d=FF(d,a,b,c,x[i+9],12,0x8b44f7af);
    c=FF(c,d,a,b,x[i+10],17,0xffff5bb1); b=FF(b,c,d,a,x[i+11],22,0x895cd7be);
    a=FF(a,b,c,d,x[i+12],7,0x6b901122); d=FF(d,a,b,c,x[i+13],12,0xfd987193);
    c=FF(c,d,a,b,x[i+14],17,0xa679438e); b=FF(b,c,d,a,x[i+15],22,0x49b40821);
    a=GG(a,b,c,d,x[i+1],5,0xf61e2562); d=GG(d,a,b,c,x[i+6],9,0xc040b340);
    c=GG(c,d,a,b,x[i+11],14,0x265e5a51); b=GG(b,c,d,a,x[i+0],20,0xe9b6c7aa);
    a=GG(a,b,c,d,x[i+5],5,0xd62f105d); d=GG(d,a,b,c,x[i+10],9,0x02441453);
    c=GG(c,d,a,b,x[i+15],14,0xd8a1e681); b=GG(b,c,d,a,x[i+4],20,0xe7d3fbc8);
    a=GG(a,b,c,d,x[i+9],5,0x21e1cde6); d=GG(d,a,b,c,x[i+14],9,0xc33707d6);
    c=GG(c,d,a,b,x[i+3],14,0xf4d50d87); b=GG(b,c,d,a,x[i+8],20,0x455a14ed);
    a=GG(a,b,c,d,x[i+13],5,0xa9e3e905); d=GG(d,a,b,c,x[i+2],9,0xfcefa3f8);
    c=GG(c,d,a,b,x[i+7],14,0x676f02d9); b=GG(b,c,d,a,x[i+12],20,0x8d2a4c8a);
    a=HH(a,b,c,d,x[i+5],4,0xfffa3942); d=HH(d,a,b,c,x[i+8],11,0x8771f681);
    c=HH(c,d,a,b,x[i+11],16,0x6d9d6122); b=HH(b,c,d,a,x[i+14],23,0xfde5380c);
    a=HH(a,b,c,d,x[i+1],4,0xa4beea44); d=HH(d,a,b,c,x[i+4],11,0x4bdecfa9);
    c=HH(c,d,a,b,x[i+7],16,0xf6bb4b60); b=HH(b,c,d,a,x[i+10],23,0xbebfbc70);
    a=HH(a,b,c,d,x[i+13],4,0x289b7ec6); d=HH(d,a,b,c,x[i+0],11,0xeaa127fa);
    c=HH(c,d,a,b,x[i+3],16,0xd4ef3085); b=HH(b,c,d,a,x[i+6],23,0x04881d05);
    a=HH(a,b,c,d,x[i+9],4,0xd9d4d039); d=HH(d,a,b,c,x[i+12],11,0xe6db99e5);
    c=HH(c,d,a,b,x[i+15],16,0x1fa27cf8); b=HH(b,c,d,a,x[i+2],23,0xc4ac5665);
    a=II(a,b,c,d,x[i+0],6,0xf4292244); d=II(d,a,b,c,x[i+7],10,0x432aff97);
    c=II(c,d,a,b,x[i+14],15,0xab9423a7); b=II(b,c,d,a,x[i+5],21,0xfc93a039);
    a=II(a,b,c,d,x[i+12],6,0x655b59c3); d=II(d,a,b,c,x[i+3],10,0x8f0ccc92);
    c=II(c,d,a,b,x[i+10],15,0xffeff47d); b=II(b,c,d,a,x[i+1],21,0x85845dd1);
    a=II(a,b,c,d,x[i+8],6,0x6fa87e4f); d=II(d,a,b,c,x[i+15],10,0xfe2ce6e0);
    c=II(c,d,a,b,x[i+6],15,0xa3014314); b=II(b,c,d,a,x[i+13],21,0x4e0811a1);
    a=II(a,b,c,d,x[i+4],6,0xf7537e82); d=II(d,a,b,c,x[i+11],10,0xbd3af235);
    c=II(c,d,a,b,x[i+2],15,0x2ad7d2bb); b=II(b,c,d,a,x[i+9],21,0xeb86d391);
    a=AU(a,oa); b=AU(b,ob); c=AU(c,oc); d=AU(d,od);
  }
  return (W2H(a)+W2H(b)+W2H(c)+W2H(d)).toLowerCase();
}

// 5) Calculate and compare
const calculated = md5(paramString);
const valid = calculated === receivedSignature;

// 6) Output
return [
  {
    json: {
      signature_valid: valid,
      signature_string: paramString,
      calculated_signature: calculated,
      received_signature: receivedSignature,
      // pass through useful fields
      payment_status: pf.payment_status,
      m_payment_id: pf.m_payment_id,
      pf_payment_id: pf.pf_payment_id,
      amount_gross: pf.amount_gross,
      amount_fee: pf.amount_fee,
      amount_net: pf.amount_net,
      name_first: pf.name_first,
      name_last: pf.name_last,
      email_address: pf.email_address,
      merchant_id: pf.merchant_id,
      item_name: pf.item_name,
      item_description: pf.item_description,
    }
  }
];

// ===== USE EXPANDED XERO LINES FROM STATE (THE CORRECT SOURCE) =====

const d = $json;

// Parse the already-expanded invoice lines from state
let lineItems = [];

try {
  if (d.invoice_lineitems_json) {
    lineItems = JSON.parse(d.invoice_lineitems_json);
  }
} catch (e) {
  throw new Error("invoice_lineitems_json is invalid JSON");
}

// Safety check
if (!Array.isArray(lineItems) || lineItems.length === 0) {
  throw new Error("No valid invoice_lineitems_json found in state");
}

// Ensure numeric fields
lineItems = lineItems.map(l => ({
  ItemCode: (l.ItemCode || "").replace(/[\r\n]/g, "").trim(),
  Description: l.Description || "",
  Quantity: Number(l.Quantity || 0),
  UnitAmount: Number(l.UnitAmount || 0),
  LineAmount: Number(l.LineAmount || 0),
  TaxType: l.TaxType || "OUTPUT3",
  AccountCode: l.AccountCode || "200"
}));

// Return exactly what Xero expects
return [
  {
    json: {
      ContactID: d.ContactID,
      LineItems: lineItems,
      Total: Number(d.order_total || 0),
      Reference: d.order_id || ""
    }
  }
];

// Rename PDF file based on invoice number
const item = $input.first();
const newName = `${item.json.Payments[0].Invoice.InvoiceNumber}.pdf`;
item.binary.data.fileName = newName;
return item;

