// Workflow 2: normalise LineItems from incoming item (no node references)

const input = $json; // this node's direct input

const ContactID = input.ContactID;
const Reference = input.Reference || input.order_id || "";
const Total = Number(input.Total ?? 0);

const raw = Array.isArray(input.LineItems) ? input.LineItems : [];

const LineItems = raw
  .map(li => {
    const ItemCode = String(li.ItemCode ?? li.itemCode ?? "")
      .replace(/[\r\n]/g, "")
      .trim();

    const Description = String(li.Description ?? li.description ?? ItemCode).trim();

    const Quantity = Number(li.Quantity ?? li.quantity ?? 0);
    const UnitAmount = Number(li.UnitAmount ?? li.unitAmount ?? 0);

    const LineAmount = Number(
      (li.LineAmount ?? li.lineAmount ?? (Quantity * UnitAmount)).toFixed(2)
    );

    const TaxType = String(li.TaxType ?? li.taxType ?? "OUTPUT3");
    const AccountCode = String(li.AccountCode ?? li.accountCode ?? "200");

    if (!ItemCode || !Number.isFinite(Quantity) || Quantity <= 0) return null;

    return { ItemCode, Description, Quantity, UnitAmount, LineAmount, TaxType, AccountCode };
  })
  .filter(Boolean);

return [
  {
    json: {
      ContactID,
      Reference,
      Total,
      LineItems,
    }
  }
];
